// ===== ACTIONS =====
function doLogin() {
  const username = document.getElementById('login-username').value.trim();
  const password = document.getElementById('login-password').value;
  if (!username || !password) {
    const errEl = document.getElementById('login-error');
    if (errEl) { errEl.textContent = 'Enter your username and password'; errEl.style.display = 'block'; }
    return;
  }
  loginWithCredentials(username, password);
}

async function loginWithCredentials(username, password) {
  try {
    const res = await apiPost("/api/login", { username, password });
    currentUser = res.user;
    await loadAllData();
    currentBracketId = null;
    currentPicks = {};
    render();
  } catch (err) {
    const errEl = document.getElementById("login-error");
    if (errEl) {
      errEl.textContent = err.message;
      errEl.style.display = "block";
    }
  }
}

function logout() {
  currentUser = null;
  currentView = "home";
  currentPicks = {};
  currentBracketId = null;
  viewingBracketId = null;
  render();
}

function navigate(view) {
  currentView = view;
  render();
  window.scrollTo(0, 0);
}

function viewProfile(userId) {
  viewingUserId = userId;
  navigate("profile");
}

function viewBracket(bracketId) {
  const bracket = allBrackets.find(b => b.id === bracketId);
  if (bracket) viewingUserId = bracket.user_id;
  viewingBracketId = bracketId;
  navigate("view-bracket");
}

function openBracket(bracketId) {
  const bracket = allBrackets.find(b => b.id === bracketId);
  if (!bracket) return;
  currentBracketId = bracketId;
  currentPicks = bracket.submitted ? {} : { ...(bracket.picks || {}) };
  render();
}

function closeBracketEditor() {
  currentBracketId = null;
  currentPicks = {};
  render();
}

async function createNewBracket() {
  try {
    const res = await apiPost("/api/brackets", { user_id: currentUser.id });
    showToast(`${res.label} created!`, "success");
    await loadAllData();
    openBracket(res.id);
  } catch (err) {
    showToast(err.message, "error");
  }
}

async function deleteBracket(bracketId) {
  if (!confirm("Delete this bracket? This cannot be undone.")) return;
  try {
    await apiDelete(`/api/brackets/${bracketId}?viewer_id=${currentUser.id}`);
    showToast("Bracket deleted", "success");
    if (currentBracketId === bracketId) {
      currentBracketId = null;
      currentPicks = {};
    }
    await loadAllData();
    render();
  } catch (err) {
    showToast(err.message, "error");
  }
}

function switchRegion(region) {
  currentRegion = region;
  render();
}

function makePick(matchKey, teamStr) {
  if (!currentBracketId) return;
  const bracket = allBrackets.find(b => b.id === currentBracketId);
  if (bracket && bracket.submitted) return;

  // If changing a pick in an earlier round, cascade clear downstream
  const oldPick = currentPicks[matchKey];
  if (oldPick && oldPick !== teamStr) {
    cascadeClear(matchKey, oldPick);
  }

  currentPicks[matchKey] = teamStr;
  render();
}

function cascadeClear(matchKey, clearedTeam) {
  // Parse the match key to find downstream matches
  const parts = matchKey.match(/^(.+)-R(\d+)-M(\d+)$/);
  if (!parts) {
    // Final Four keys
    if (matchKey === "FF-SF1" || matchKey === "FF-SF2") {
      const champPick = currentPicks["FF-CHAMP"];
      if (champPick === clearedTeam) {
        delete currentPicks["FF-CHAMP"];
      }
    }
    return;
  }

  const [, region, roundStr, matchStr] = parts;
  const round = parseInt(roundStr);
  const match = parseInt(matchStr);

  if (round < 3) {
    const nextKey = `${region}-R${round + 1}-M${Math.floor(match / 2)}`;
    const nextPick = currentPicks[nextKey];
    if (nextPick === clearedTeam) {
      delete currentPicks[nextKey];
      cascadeClear(nextKey, clearedTeam);
    }
  } else if (round === 3) {
    // E8 winner feeds into Final Four
    if (region === "East" || region === "West") {
      const sfPick = currentPicks["FF-SF1"];
      if (sfPick === clearedTeam) {
        delete currentPicks["FF-SF1"];
        const champPick = currentPicks["FF-CHAMP"];
        if (champPick === clearedTeam) delete currentPicks["FF-CHAMP"];
      }
    } else {
      const sfPick = currentPicks["FF-SF2"];
      if (sfPick === clearedTeam) {
        delete currentPicks["FF-SF2"];
        const champPick = currentPicks["FF-CHAMP"];
        if (champPick === clearedTeam) delete currentPicks["FF-CHAMP"];
      }
    }
  }
}

async function saveDraft() {
  if (!currentBracketId) return;
  try {
    await apiPut(`/api/brackets/${currentBracketId}/picks`, { picks: currentPicks });
    showToast("Draft saved", "success");
    await loadAllData();
  } catch (err) {
    showToast(err.message, "error");
  }
}

function confirmSubmit() {
  const pickCount = Object.keys(currentPicks).length;
  const overlay = document.createElement("div");
  overlay.className = "modal-overlay";
  overlay.innerHTML = `
    <div class="modal-card">
      <h3>Submit Bracket?</h3>
      <p>You have ${pickCount} picks. Once submitted, your bracket is locked — no changes allowed. Entry fee: <strong>$${config.entry_fee}</strong></p>
      <div class="modal-buttons">
        <button class="btn-secondary" onclick="this.closest('.modal-overlay').remove()">Cancel</button>
        <button class="btn-primary orange" style="width:auto;padding:10px 24px;" onclick="submitBracket(); this.closest('.modal-overlay').remove();">Submit & Lock</button>
      </div>
    </div>
  `;
  document.body.appendChild(overlay);
}

async function submitBracket() {
  if (!currentBracketId) return;
  try {
    await apiPost(`/api/brackets/${currentBracketId}/submit`, { picks: currentPicks });
    showToast("Bracket submitted and locked!", "success");
    await loadAllData();
    render();
  } catch (err) {
    showToast(err.message, "error");
  }
}

function toggleCreateBet() {
  const form = document.getElementById("create-bet-form");
  if (form) form.style.display = form.style.display === "none" ? "block" : "none";
}

async function createBet() {
  const amount = parseFloat(document.getElementById("bet-amount").value);
  const desc = document.getElementById("bet-description").value.trim();
  const aboutId = parseInt(document.getElementById("bet-about").value);

  if (!aboutId) {
    showToast("Select a member for your bet", "error");
    return;
  }
  if (!amount || !desc) {
    showToast("Fill out all fields", "error");
    return;
  }

  try {
    await apiPost(`/api/bets?viewer_id=${currentUser.id}`, {
      about_user_id: aboutId,
      description: desc,
      amount: amount,
    });
    showToast("Bet created!", "success");
    await loadBets();
    render();
  } catch (err) {
    showToast(err.message, "error");
  }
}

async function takeBet(betId) {
  try {
    await apiPost(`/api/bets/${betId}/take?viewer_id=${currentUser.id}`, {});
    showToast("You took the bet!", "success");
    await loadBets();
    render();
  } catch (err) {
    showToast(err.message, "error");
  }
}

async function deleteBet(betId) {
  try {
    await apiDelete(`/api/bets/${betId}?viewer_id=${currentUser.id}`);
    showToast("Bet deleted", "success");
    await loadBets();
    render();
  } catch (err) {
    showToast(err.message, "error");
  }
}

// Admin actions
async function addMember() {
  const name = document.getElementById("admin-name").value.trim();
  const email = document.getElementById("admin-email").value.trim();
  const username = document.getElementById("admin-username").value.trim();
  const password = document.getElementById("admin-password").value.trim();
  const isAdmin = document.getElementById("admin-is-admin").checked ? 1 : 0;

  if (!name || !email || !username || !password) {
    showToast("All fields required (name, email, username, password)", "error");
    return;
  }

  try {
    await apiPost("/api/admin/users", { email, username, password, display_name: name, is_admin: isAdmin });
    showToast(`${name} added! Username: ${username}`, "success");
    await loadAllData();
    render();
  } catch (err) {
    showToast(err.message, "error");
  }
}

async function promptResetPassword(userId, displayName) {
  const newPw = prompt(`Enter new password for ${displayName}:`);
  if (!newPw) return;
  try {
    await apiPost(`/api/admin/reset-password/${userId}`, { password: newPw });
    showToast(`Password reset for ${displayName}`, "success");
  } catch (err) {
    showToast(err.message, "error");
  }
}

async function removeMember(userId) {
  if (!confirm("Remove this member? This deletes their bracket and all related bets.")) return;
  try {
    await apiDelete(`/api/admin/users/${userId}`);
    showToast("Member removed", "success");
    await loadAllData();
    render();
  } catch (err) {
    showToast(err.message, "error");
  }
}

let avatarUploadUserId = null;
function triggerAvatarUpload(userId) {
  avatarUploadUserId = userId;
  document.getElementById("avatar-file-input").click();
}

async function handleAvatarUpload(file) {
  if (!avatarUploadUserId || !file) return;
  const formData = new FormData();
  formData.append("file", file);

  try {
    const res = await fetch(`${API}/api/admin/avatar/${avatarUploadUserId}`, {
      method: "POST",
      body: formData,
    });
    if (!res.ok) throw new Error("Upload failed");
    showToast("Photo uploaded!", "success");
    await loadAllData();
    render();
  } catch (err) {
    showToast(err.message, "error");
  }
}

// ===== DATA LOADING =====
async function loadAllData() {
  const [users, brackets, betsRes, cfg] = await Promise.all([
    apiGet("/api/users"),
    apiGet("/api/brackets"),
    apiGet(`/api/bets?viewer_id=${currentUser ? currentUser.id : 0}`),
    apiGet("/api/config"),
  ]);
  allUsers = users;
  allBrackets = brackets;
  betData = betsRes;
  config = cfg;
}

async function loadBets() {
  betData = await apiGet(`/api/bets?viewer_id=${currentUser ? currentUser.id : 0}`);
}

// ===== EVENT BINDING =====
function bindEvents() {
  const loginForm = document.getElementById("login-form");
  if (loginForm) {
    loginForm.addEventListener("submit", (e) => {
      e.preventDefault();
      const email = document.getElementById("login-email").value;
      login(email);
    });
  }

  const avatarInput = document.getElementById("avatar-file-input");
  if (avatarInput) {
    avatarInput.addEventListener("change", (e) => {
      if (e.target.files[0]) handleAvatarUpload(e.target.files[0]);
    });
  }
}

function escapeHtml(str) {
  const div = document.createElement("div");
  div.textContent = str;
  return div.innerHTML;
}

// ===== INIT =====
async function init() {
  try {
    config = await apiGet("/api/config");
  } catch (e) {}
  render();
}

init();
